namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil."],
            Ratings = [5, 4, 5, 4, 5]
        },
        new()
        {
            Id = 2,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken until charred.", "Sauté onions, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Serve over basmati rice."],
            Ratings = [5, 5, 4, 5]
        },
        new()
        {
            Id = 3,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in the oven.", "Assemble tacos with beef, lettuce, tomato, and cheese.", "Top with sour cream and serve."],
            Ratings = [4, 4, 3, 5, 4]
        },
        new()
        {
            Id = 4,
            Title = "Pad Thai",
            Category = "Thai",
            Ingredients = ["Rice noodles", "Shrimp", "Egg", "Bean sprouts", "Peanuts", "Lime", "Fish sauce", "Tamarind paste", "Sugar"],
            Steps = ["Soak rice noodles in warm water for 30 minutes.", "Stir-fry shrimp until pink, set aside.", "Scramble egg in the wok.", "Add noodles, fish sauce, tamarind, and sugar.", "Toss with shrimp and bean sprouts.", "Serve with crushed peanuts and lime wedges."],
            Ratings = [5, 4, 5]
        },
        new()
        {
            Id = 5,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = ["Spaghetti", "Guanciale", "Eggs", "Pecorino Romano", "Black pepper"],
            Steps = ["Cook spaghetti in salted water until al dente.", "Crisp guanciale in a pan.", "Whisk eggs with grated pecorino and pepper.", "Toss hot pasta with guanciale off heat.", "Quickly stir in egg mixture to create a creamy sauce.", "Serve immediately with extra pecorino."],
            Ratings = [5, 5, 5, 4, 5]
        },
        new()
        {
            Id = 6,
            Title = "French Onion Soup",
            Category = "French",
            Ingredients = ["Onions", "Butter", "Beef broth", "White wine", "Baguette", "Gruyère cheese", "Thyme"],
            Steps = ["Slice onions thinly and caramelize in butter for 45 minutes.", "Deglaze with white wine.", "Add beef broth and thyme, simmer 20 minutes.", "Ladle into oven-safe bowls.", "Top with baguette slices and gruyère.", "Broil until cheese is bubbly and golden."],
            Ratings = [4, 5, 4, 4]
        }
    ];

    private int _nextId = 7;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars is >= 1 and <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public void AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services

<div class="star-rating my-3">
    <span class="me-2 text-muted">Rate this recipe:</span>
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              role="button"
              title="@star star(s)">
            @(star <= _selectedRating ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private int _selectedRating;
    private bool _submitted;

    private void Rate(int stars)
    {
        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
    }
}

@page "/"
@using RecipeCommunity.Services

<PageTitle>Recipe Community</PageTitle>

<div class="text-center mb-4">
    <h1 class="display-4">🍳 Recipe Community</h1>
    <p class="lead">Discover and share delicious recipes from around the world</p>
</div>

<h2 class="mb-3">Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100 shadow-sm">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetCategoryEmoji(category) @category</h4>
                    <p class="text-muted">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="/category/@category" class="btn btn-outline-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Mexican" => "🇲🇽",
        "Thai" => "🇹🇭",
        "French" => "🇫🇷",
        _ => "🍽️"
    };
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@CategoryName Recipes</PageTitle>

<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        <li class="breadcrumb-item active">@CategoryName</li>
    </ol>
</nav>

<h1>@CategoryName Recipes</h1>

@if (_recipes.Count == 0)
{
    <p class="text-muted">No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in _recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="text-warning mb-1">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <span class="text-muted ms-1">(@recipe.AverageRating.ToString("F1"))</span>
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-sm btn-primary mt-2">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter] public string CategoryName { get; set; } = string.Empty;
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private List<Recipe> _recipes = [];

    protected override void OnParametersSet()
    {
        _recipes = RecipeService.GetByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@using RecipeCommunity.Models

<PageTitle>@(_recipe?.Title ?? "Recipe")</PageTitle>

@if (_recipe is null)
{
    <p class="text-danger">Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item"><a href="/category/@_recipe.Category">@_recipe.Category</a></li>
            <li class="breadcrumb-item active">@_recipe.Title</li>
        </ol>
    </nav>

    <h1>@_recipe.Title</h1>
    <p class="text-warning fs-5">
        @for (int i = 1; i <= 5; i++)
        {
            @(i <= (int)Math.Round(_recipe.AverageRating) ? "★" : "☆")
        }
        <span class="text-muted ms-2">@_recipe.AverageRating.ToString("F1") (@_recipe.Ratings.Count ratings)</span>
    </p>

    <h3 class="mt-4">Ingredients</h3>
    <ul class="list-group list-group-flush mb-4">
        @foreach (var ingredient in _recipe.Ingredients)
        {
            <li class="list-group-item">@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol class="list-group list-group-numbered mb-4">
        @foreach (var step in _recipe.Steps)
        {
            <li class="list-group-item">@step</li>
        }
    </ol>

    <StarRating RecipeId="@_recipe.Id" />
}

@code {
    [Parameter] public int Id { get; set; }
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private Recipe? _recipe;

    protected override void OnParametersSet()
    {
        _recipe = RecipeService.GetById(Id);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services

<PageTitle>Submit a Recipe</PageTitle>

<h1>Submit a Recipe</h1>
<p class="text-muted">Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <strong>Recipe submitted!</strong> Your recipe has been added to the community.
        <a href="/category/@_category">View it here</a>.
    </div>
}
else
{
    <div class="card shadow-sm">
        <div class="card-body">
            <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                <div class="mb-3">
                    <label class="form-label">Recipe Title</label>
                    <InputText @bind-Value="_title" class="form-control" placeholder="e.g. Grandma's Apple Pie" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Category</label>
                    <InputSelect @bind-Value="_category" class="form-select">
                        <option value="">Select a category...</option>
                        @foreach (var cat in RecipeService.GetCategories())
                        {
                            <option value="@cat">@cat</option>
                        }
                        <option value="American">American</option>
                        <option value="Japanese">Japanese</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>

                <div class="mb-3">
                    <label class="form-label">Ingredients (one per line)</label>
                    <InputTextArea @bind-Value="_ingredientsText" class="form-control" rows="5"
                                   placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
                </div>

                <div class="mb-3">
                    <label class="form-label">Steps (one per line)</label>
                    <InputTextArea @bind-Value="_stepsText" class="form-control" rows="5"
                                   placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Bake for 30 minutes." />
                </div>

                <button type="submit" class="btn btn-primary"
                        disabled="@(!IsFormValid)">
                    Submit Recipe
                </button>
            </EditForm>
        </div>
    </div>
}

@code {
    [Inject] private RecipeService RecipeService { get; set; } = default!;

    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _ingredientsText = string.Empty;
    private string _stepsText = string.Empty;
    private bool _submitted;

    private bool IsFormValid =>
        !string.IsNullOrWhiteSpace(_title) &&
        !string.IsNullOrWhiteSpace(_category) &&
        !string.IsNullOrWhiteSpace(_ingredientsText) &&
        !string.IsNullOrWhiteSpace(_stepsText);

    private void HandleSubmit()
    {
        if (!IsFormValid) return;

        var ingredients = _ingredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = _stepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        RecipeService.AddRecipe(_title, _category, ingredients, steps);
        _submitted = true;
    }
}

