            Ratings = [5, 4, 5]
        },
        new()
        {
            Id = 5,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = ["Spaghetti", "Guanciale", "Eggs", "Pecorino Romano", "Black pepper"],
